/// Persistent light-client state PDA.
///
/// Seeds: `[b"light_client_state"]`. One per zkTempo verifier deployment.
#[account]
pub struct LightClientState {
    /// Most recently finalized Tempo slot.
    pub latest_slot: u64,
    /// State root finalized at `latest_slot`.
    pub state_root: [u8; 32],
    /// Hash commitment of the active validator set.
    pub validator_set_hash: [u8; 32],
    /// Solana `Clock::unix_timestamp` at the last update. Used by
    /// downstream consumers to detect stale roots.
    pub last_update_unix_ts: i64,
    /// PDA bump seed.
    pub bump: u8,
}

impl LightClientState {
    pub const SEED: &'static [u8] = b"light_client_state";
    /// Size in bytes, **excluding** the 8-byte Anchor discriminator.
    /// u64 (8) + [u8;32] (32) + [u8;32] (32) + i64 (8) + u8 (1) = 81.
    pub const SIZE: usize = 8 + 32 + 32 + 8 + 1;
}

#[derive(Accounts)]
pub struct Bootstrap<'info> {
    #[account(
        init,
        payer = authority,
        space = 8 + LightClientState::SIZE,
        seeds = [LightClientState::SEED],
        bump,
    )]
    pub light_client_state: Account<'info, LightClientState>,
    #[account(mut)]
    pub authority: Signer<'info>,
    pub system_program: Program<'info, System>,
}

#[derive(Accounts)]
pub struct UpdateLightClient<'info> {
    #[account(
        mut,
        seeds = [LightClientState::SEED],
        bump = light_client_state.bump,
    )]
    pub light_client_state: Account<'info, LightClientState>,
    /// The fee-payer for the update transaction. Not an authority — the
    /// proof is the authority.
    pub submitter: Signer<'info>,
}

#[error_code]
pub enum ZkTempoError {
    #[msg("Groth16 proof verification failed")]
    InvalidProof,
    #[msg("New slot must be strictly greater than the latest finalized slot")]
    NonMonotonicSlot,
    #[msg("Validator set hash does not match the active set")]
    StaleValidatorSet,
    #[msg("Public inputs do not match proof commitments")]
    PublicInputMismatch,
}
